107	// Subscribe opens a GraphQL WebSocket subscription and streams raw payloads
108	// from graphql-transport-ws next messages.
109	func (t *WebSocketSubscriptionTransport) Subscribe(ctx context.Context, query string, variables map[string]any) (<-chan json.RawMessage, error) {
110		url := normalizeWebSocketURL(strings.TrimSpace(t.URL))
111		if url == "" {
112			return nil, fmt.Errorf("axon: websocket subscription url is required")
113		}
114	
115		dialer := websocket.DefaultDialer
116		if t.Dialer != nil {
117			dialer = t.Dialer
118		}
119		if len(dialer.Subprotocols) == 0 {
120			dialer = cloneDialer(dialer)
121			dialer.Subprotocols = []string{graphqlWSSubprotocol}
122		}
123	
124		header := cloneHeader(t.Header)
125		conn, _, err := dialer.DialContext(ctx, url, header)
126		if err != nil {
127			return nil, fmt.Errorf("axon: websocket dial: %w", err)
128		}
129	
130		closed := make(chan struct{})
131		var closeOnce sync.Once
132		cleanup := func() {
133			closeOnce.Do(func() {
134				close(closed)
135				_ = conn.Close()
136			})
137		}
138		go func() {
139			select {
140			case <-ctx.Done():
141				cleanup()
142			case <-closed:
143			}
144		}()
145	
146		if conn.Subprotocol() != "" && conn.Subprotocol() != graphqlWSSubprotocol {
147			cleanup()
148			return nil, fmt.Errorf("axon: websocket subprotocol mismatch: got %q want %q", conn.Subprotocol(), graphqlWSSubprotocol)
149		}
150	
151		if err := conn.WriteJSON(graphqlWSMessage{Type: "connection_init", Payload: mustJSON(t.InitPayload)}); err != nil {
152			cleanup()
153			return nil, fmt.Errorf("axon: websocket connection_init: %w", err)
154		}
155	
156		for {
157			var msg graphqlWSMessage
158			if err := conn.ReadJSON(&msg); err != nil {
159				cleanup()
160				return nil, fmt.Errorf("axon: websocket ack: %w", err)
161			}
162			switch msg.Type {
163			case "connection_ack":
164				goto subscribed
165			case "ping":
166				_ = conn.WriteJSON(graphqlWSMessage{Type: "pong"})
167			case "error":
168				cleanup()
169				return nil, fmt.Errorf("axon: websocket connection error")
170			}
171		}
172	
173	subscribed:
174		subPayload, err := json.Marshal(map[string]any{
175			"query":     query,
176			"variables": variables,
177		})
178		if err != nil {
179			cleanup()
180			return nil, fmt.Errorf("axon: websocket subscribe payload: %w", err)
181		}
182		if err := conn.WriteJSON(graphqlWSMessage{ID: "1", Type: "subscribe", Payload: subPayload}); err != nil {
183			cleanup()
184			return nil, fmt.Errorf("axon: websocket subscribe: %w", err)
185		}
186	
187		out := make(chan json.RawMessage)
188		go func() {
189			defer close(out)
190			defer cleanup()
191			for {
192				var msg graphqlWSMessage
193				if err := conn.ReadJSON(&msg); err != nil {
194					return
195				}
196				switch msg.Type {
197				case "next":
198					if len(msg.Payload) == 0 {
199						continue
200					}
201					payload := append(json.RawMessage(nil), msg.Payload...)
202					select {
203					case out <- payload:
204					case <-ctx.Done():
205						return
206					}
207				case "complete":
208					return
209				case "ping":
210					_ = conn.WriteJSON(graphqlWSMessage{Type: "pong"})
211				case "error":
212					return
213				}
214			}
215		}()
216	
217		return out, nil
218	}
