243	func cloneHeader(src http.Header) http.Header {
244		if len(src) == 0 {
245			return http.Header{}
246		}
247		dst := make(http.Header, len(src))
248		for k, values := range src {
249			dst[k] = append([]string(nil), values...)
250		}
251		return dst
252	}
