254	func cloneDialer(src *websocket.Dialer) *websocket.Dialer {
255		if src == nil {
256			return &websocket.Dialer{}
257		}
258		cp := *src
259		cp.Subprotocols = append([]string(nil), src.Subprotocols...)
260		return &cp
261	}
